INSERT INTO `preventivi` (`id`, `idp`, `numero`, `rev`, `data`, `idcliente`, `daticliente`, `titolo`, `titolo1`, `titolo2`, `descrizione`, `descrizione1`, `descrizione2`, `totaleprev`, `scontoprev`, `totalescontatoprev`, `conferma`, `stato`, `note`, `noteprezzieprev`, `tempi_consegna`, `pagamento`, `accettazionepreventivo`, `mostraiva`) VALUES
(95, 0, 1, '', '2017-01-05', 703, 'Antonio Sposito\r\nErboristeria Corradi\r\n42121 Reggio Emilia (RE)', 'Realizzazione sito web Erboristeria Corradi', 'HOSTING', '', '<p>Realizzazione, di sito web dinamico (aggiornabile dall\'utente), con collegato nostro CMS, secondo le specifiche da voi indicate: sito <a href=\"http://www.marius-fabre.com\">www.marius-fabre.com</a> come modello</p>\r\n<p>Il sito sar&agrave; strutturato con pagine istituzionali(chi siamo, dove siamo, etc..) e un catalogo prodotti interamente gestibile dall\'utente.</p>\r\n<p><br />Il sito sar&agrave; realizzato secondo gli standard del momento e sar&agrave; responsive, cio&egrave; perfettamente visualizzabile su qualsiasi dispositivo, smartphone, tablet, pc, notebook, ecc</p>', '<p>Preparazione ambiente di lavoro, registrazione o trasferimento dominio, canone hosting e posta elettronica 1 anno, compresi nel presente preventivo.</p>\r\n<p>Canone anni successivi, 120&euro; + iva anno (a partire da 01/01/2018).</p>\r\n<p>Il canone comprende, oltre a piccoli aggiustamenti e modifiche, tutto ci&ograve; che &egrave; indicato alla voce \'REGISTRARE E SVILUPPARE IL SITO CON NOI, TUTTO INCLUSO\'</p>', '', 800.00, 0.00, 800.00, '', '1', '', '', 'Da concordare con il cliente', '30% alla firma, il rimanente da concordare col cliente', '1', '1'),
(96, 0, 2, '', '2017-01-10', 35, 'Antonella Margini\r\nFI.MA di Masini & Figli s.r.l.\r\nC.F. IT00672870359\r\nP.Iva IT00672870359\r\nVia Maresciallo Tito, 65/A Montecavolo\r\n42020 Quattro Castella (RE)', 'Restyling sito web www.fima-arredo.it', '', '', '<p>Il sito attuale sar&agrave; modificato nella grafica e nella struttura, in modo da&nbsp; adeguarsi agli standard attuali:</p>\r\n<p>1. aumento dello spazio utile in larghezza e migliore organizzazione delle informazioni</p>\r\n<p>2. versione responsive per una corretta visualizzazione su tutti i dispositivi, desktop, tablet e smartphone</p>\r\n<p>3. inserimento della nuova categoria Giochi</p>\r\n<p>4. valorizzazione della sezione news, per inserire le ultime realizzazioni fatte</p>\r\n<p>&nbsp;</p>\r\n<p>E\' presente una bozza assolutamente non vincolante a questo indirizzo</p>\r\n<p><a href=\"http://hostclicom.com/fima/\">http://hostclicom.com/fima/</a></p>\r\n<p>&nbsp;</p>\r\n<p>Per il completamento della bozza o lo sviluppo di nuove idee saranno presi come riferimento i seguenti siti:</p>\r\n<p><a href=\"http://moroso.it/\">http://www.moroso.it/</a></p>\r\n<p><a href=\"http://www.rodaonline.com\">http://www.rodaonline.com</a></p>\r\n<p><a href=\"https://www.dedon.de/\">https://www.dedon.de/</a></p>\r\n<p>&nbsp;</p>', '', '', 800.00, 0.00, 800.00, '', '1', '', '', 'da concordare', 'bonifico 60gg fine mese', '1', '1'),
(97, 0, 3, '', '2017-01-11', 10, 'Prisca Patrizi\r\nQuadra srl\r\nvia Scarabelli Zunti ,3\r\n43123 Parma (PR)\r\nC.F. 1887510343\r\nP.Iva 1887510343', 'Realizzazione sito web con prodotti', 'Registrare il sito web con noi tutto compreso', 'Risorse e tecnologie', '<p>Realizzeremo il sito web secondo i pi&ugrave; attuali standard del momento e con le tecnologie migliori, HTML, CSS3, php, jquery, mysql, javascript.<br /><br />Il sito sar&agrave; ottimizzato per la corretta visualizzazione su smartphone e tablet (sito web responsive) e si visualizzer&agrave; perfettamente anche su tutti gli altri dispositivi e sistemi operativi.<br /><br />Sar&agrave; nostra cura rispettare i vari adempimenti obbligatori:</p>\r\n<ul>\r\n<li>cookie policy</li>\r\n<li>privacy</li>\r\n<li>termini e utilizzo dei dati</li>\r\n</ul>', '<ul>\r\n<li>Registrazione o trasferimento dominio gratuito</li>\r\n<li>Canone hosting primo anno gratuito</li>\r\n<li>Servizio e-mail professionale pop3/imap</li>\r\n<li>SMTP autenticato senza limiti di invio</li>\r\n<li>Caselle e-mail illimitate</li>\r\n<li>Sottodomini illimitati</li>\r\n<li>Database illimitati</li>\r\n</ul>', '<ul>\r\n<li>Risorse dedicate al progetto: 1 programmatore, 1 grafico</li>\r\n<li>Tecnologia di programmazione: HTML5, css3, jquery, javascript, php e mysql</li>\r\n<li>Server dedicato linux con backup giornaliero</li>\r\n</ul>', 800.00, 0.00, 800.00, '', '1', 'Il cms con la sua programmazione e la sua grafica, sono di proprietÃ  di Clicom snc, il sito e i suoi contenuti sono di proprietÃ  del cliente', 'Preparazione ambiente, canone primo anno, registrazione, o trasferimento, dominio sui nostri server, canone primo anno compreso nel presente preventivo.\r\nCanone hosting e posta elettronica anni successivi, 120â‚¬ + iva annui', '20-25 giorni da conferma preventivo e ricevuto acconto', '30% alla firma del presente preventivo, il rimanente da concordare col cliente', '1', '1'),
(100, 0, 4, '', '2017-01-16', 115, 'Ristoservice srl\r\nC.F. 2335450355\r\nP.Iva 2335450355\r\nVia Fainardi Pietro, 16\r\n43126 Parma (PR)', 'Attivazione WGEST e personalizzazione procedure magazzino', '', '', '<p>L\'offerta prevede l\'attivazione dei moduli WGEST:</p>\r\n<ul>\r\n<li>Clienti/Fornitori</li>\r\n<li>Magazzino</li>\r\n<li>Ddt</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>Saranno implementate alcune funzioni personalizzate, secondo vostre indicazioni :</p>\r\n<ul>\r\n<li>integrazione del magazzino con generazione etichetta di stampa codice seriale e possibilit&agrave; di lettura codice a barre</li>\r\n<li>esportazione dati magazzino su attuale gestionale</li>\r\n</ul>', '', '', 750.00, 0.00, 750.00, '', '1', '', '', 'da concordare', 'RiBa 30gg FM', '1', '1'),
